#include <bits/stdc++.h>
using namespace std;
int a[6][11],b[6][11],c[6]={1,1,1,1,1,1};
int minn=2147483647,wh,ans;
int main(){
	for(int i=1;i<=5;i++)
		for(int j=1;j<=10;j++){
			cin>>a[i][j];
			b[i][j]=a[i][j]-a[i][j-1];
		}
	for(int i=1;i<=20;i++){
		minn=2147483647;
		for(int j=1;j<=5;j++){
			if(b[j][c[j]+1]<minn && c[j]+1<11){
				minn=b[j][c[j]+1];
				wh=j;
			}
		}
		c[wh]++;
	}
	for(int i=1;i<6;i++){
        ans+=a[i][c[i]];
    }
    cout<<ans<<endl;
    for(int i=1;i<6;i++)cout<<c[i]<<' ';
	return 0;
}
